import 'package:flutter_fractals/core/models/fractal_parameter.dart';

/// Numeric bounds derived from a [FractalParameter] schema.
///
/// Integer schemas store bounds as doubles because they share the numeric
/// parameter contract with float sliders. [containsInteger] exposes the hidden
/// assumption that those double bounds still include at least one valid integer
/// value before integer rounding is applied.
final class FractalNumericParamBounds {
  const FractalNumericParamBounds({
    required this.min,
    required this.max,
  });

  factory FractalNumericParamBounds.fromSchema(FractalParameter schema) {
    return FractalNumericParamBounds(min: schema.min, max: schema.max);
  }

  final double min;
  final double max;

  bool get containsInteger => min.ceil() <= max.floor();

  double normalizeFloat(double value) => value.clamp(min, max).toDouble();

  int normalizeInteger(double value) {
    assert(
      containsInteger,
      'integer parameter bounds must include at least one integer value',
    );
    final rounded = normalizeFloat(value).round();
    if (!containsInteger) return rounded;
    return rounded.clamp(min.ceil(), max.floor()).toInt();
  }
}

/// Normalizes raw parameter values against a module parameter schema.
///
/// This keeps replayed state, presets, and direct UI updates on the same
/// contract: finite numeric values clamp to schema bounds after type coercion,
/// enum values must be one of the declared options, booleans must be real
/// booleans, and non-finite numeric values fall back to the schema default
/// instead of being promoted to an arbitrary bound.
Object normalizeFractalParamValue(FractalParameter schema, Object value) {
  if (schema.type == FractalParamType.boolean) {
    return value is bool ? value : _booleanDefault(schema);
  }
  if (schema.type == FractalParamType.enumeration) {
    final optionValues = schema.options.map((option) => option.value).toSet();
    return optionValues.contains(value) ? value : schema.defaultValue;
  }

  final numericValue = _finiteNumericValue(value);
  if (numericValue != null) {
    final bounds = FractalNumericParamBounds.fromSchema(schema);
    if (schema.type == FractalParamType.integer) {
      return bounds.normalizeInteger(numericValue);
    }
    return bounds.normalizeFloat(numericValue);
  }
  return schema.defaultValue;
}

double? _finiteNumericValue(Object value) {
  if (value is! num) return null;
  final numericValue = value.toDouble();
  return numericValue.isFinite ? numericValue : null;
}

bool _booleanDefault(FractalParameter schema) {
  final defaultValue = schema.defaultValue;
  return defaultValue is bool ? defaultValue : false;
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_value_normalizer.dart';
import 'package:flutter_test/flutter_test.dart';

String _label(_) => 'Parameter';

FractalParameter _booleanParam({required bool defaultValue}) {
  return FractalParameter(
    id: 'enabled',
    label: _label,
    type: FractalParamType.boolean,
    min: 0,
    max: 1,
    step: 1,
    defaultValue: defaultValue,
  );
}

FractalParameter _numericParam({
  required FractalParamType type,
  required Object defaultValue,
  double min = 1,
  double max = 10,
}) {
  return FractalParameter(
    id: 'value',
    label: _label,
    type: type,
    min: min,
    max: max,
    step: 1,
    defaultValue: defaultValue,
  );
}

void main() {
  group('normalizeFractalParamValue', () {
    test('preserves real boolean parameter values', () {
      final schema = _booleanParam(defaultValue: true);

      expect(normalizeFractalParamValue(schema, true), isTrue);
      expect(normalizeFractalParamValue(schema, false), isFalse);
    });

    test('falls back to boolean schema default for non-boolean values', () {
      expect(
        normalizeFractalParamValue(_booleanParam(defaultValue: true), 'true'),
        isTrue,
      );
      expect(
        normalizeFractalParamValue(_booleanParam(defaultValue: false), 1),
        isFalse,
      );
    });

    test('falls back to numeric schema default for non-finite numbers', () {
      final floatSchema = _numericParam(
        type: FractalParamType.float,
        defaultValue: 4.0,
      );
      final intSchema = _numericParam(
        type: FractalParamType.integer,
        defaultValue: 4,
      );

      for (final candidate in [
        double.nan,
        double.infinity,
        double.negativeInfinity,
      ]) {
        expect(
          normalizeFractalParamValue(floatSchema, candidate),
          4.0,
          reason: 'float candidate=$candidate',
        );
        expect(
          normalizeFractalParamValue(intSchema, candidate),
          4,
          reason: 'integer candidate=$candidate',
        );
      }
    });

    test('keeps rounded integer values inside fractional schema bounds', () {
      final schema = _numericParam(
        type: FractalParamType.integer,
        defaultValue: 4,
        min: 1.2,
        max: 10.8,
      );
      final bounds = FractalNumericParamBounds.fromSchema(schema);

      expect(bounds.containsInteger, isTrue);
      expect(normalizeFractalParamValue(schema, 1.2), 2);
      expect(normalizeFractalParamValue(schema, 10.8), 10);
    });
  });
}

import 'dart:async';
import 'dart:math';
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/services/test_logger.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_controller_snapshots.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_effect_input_bounds.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_kaleidoscope_state.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_randomizer.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_value_normalizer.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_view_input_bounds.dart';
import 'package:flutter_fractals/core/services/runtime_mode_service.dart';
import 'package:vector_math/vector_math.dart';

/// Manages the state of fractal rendering and user interactions.
///
/// [FractalController] is the central state manager for the fractal viewer.
/// It handles:
/// - **Module selection**: Switching between fractal types
/// - **Parameter updates**: Modifying fractal settings with validation
/// - **View transformations**: Pan, zoom, and rotation
/// - **Preset management**: Applying and randomizing configurations
///
/// This controller uses [ChangeNotifier] for reactive updates and is
/// typically provided via the Provider package.
///
/// {@category State Management}
///
/// Example usage:
/// ```dart
/// final controller = FractalController(registry);
///
/// // Switch fractal type
/// controller.selectModule(registry.byId('julia'));
///
/// // Update a parameter
/// controller.updateParam('iterations', 150);
///
/// // Apply a preset
/// controller.applyPreset(myPreset);
///
/// // Reset to defaults
/// controller.resetSession();
/// ```
class FractalController extends ChangeNotifier {
  static const bool _adaptiveIterationsEnabled = bool.fromEnvironment(
    'ADAPTIVE_ITERATIONS',
    defaultValue: true,
  );
  static const int _adaptiveIterationsMinStep = 8;
  static const double _adaptiveZoomEpsilon = 1.01;

  // Test mode detection - skip timer-based animations in automated tests.
  bool get _isTest => RuntimeModeService.isAutomatedTest;

  /// The module registry containing all available fractal types.
  final ModuleRegistry registry;

  final TestLogger? _logger;
  late FractalModule _module;
  Map<String, Object> _params = {};
  FractalViewState _view = FractalViewState.initial();
  bool _transparentBackground = false;
  bool _rotationLocked = false;
  bool _glowEnabled = false;
  double _glowSigma = 1.0; // blur radius multiplier: 1.0 = standard
  double _glowIntensity = 0.35; // opacity of glow layer

  // Animation state
  bool _isMorphing = false;
  double _morphProgress = 1.0;
  String? _previousModuleId;
  Timer? _morphTimer;
  bool _isCelebrating = false;
  Timer? _celebrationTimer;

  // Interesting spot tracking for celebrations
  int _consecutiveInterestingSpots = 0;
  DateTime? _lastInterestingSpotTime;
  final _celebrationController = StreamController<void>.broadcast();
  double _lastAdaptiveZoom = 1.0;

  /// Creates a new [FractalController] with the given [registry].
  ///
  /// Optionally accepts a [logger] for test instrumentation.
  /// Initializes with the first module in the registry.
  FractalController(this.registry, {TestLogger? logger}) : _logger = logger {
    _module = registry.modules.first;
    _applyPreset(_module.defaultPreset);
    _applyKaleidoscopeModulePolicy(_module.id);
    _lastAdaptiveZoom = _view.zoom;
  }

  /// Whether a module morph transition is in progress.
  bool get isMorphing => _isMorphing;

  /// Progress of the current morph transition (0.0 to 1.0).
  double get morphProgress => _morphProgress;

  /// The previous module ID during a morph transition.
  String? get previousModuleId => _previousModuleId;

  /// Whether a celebration effect should be shown.
  bool get isCelebrating => _isCelebrating;

  /// Stream that emits when a celebration should be triggered.
  Stream<void> get onCelebration => _celebrationController.stream;

  /// The currently selected fractal module.
  ///
  /// Determines which fractal type is being rendered and
  /// what parameters are available.
  FractalModule get module => _module;

  /// Current parameter values keyed by parameter ID.
  ///
  /// These are passed to the shader each frame via [FractalRenderState].
  /// Public reads receive a read-only snapshot; use [updateParam] to mutate.
  Map<String, Object> get params => snapshotFractalControllerParams(_params);

  /// Current view state (pan, zoom, rotation).
  ///
  /// Updated by gesture handlers and preset application.
  /// Public reads receive cloned vectors; use view update methods to mutate.
  FractalViewState get view => snapshotFractalControllerView(_view);

  /// Whether the fractal should render with a transparent background.
  ///
  /// Used for transparent PNG export.
  bool get transparentBackground => _transparentBackground;

  /// Whether gesture-based rotation is locked.
  bool get rotationLocked => _rotationLocked;

  bool get glowEnabled => _glowEnabled;
  double get glowSigma => _glowSigma;
  double get glowIntensity => _glowIntensity;

  // Kaleidoscope state
  bool _kaleidoscopeEnabled = false;
  int _kaleidoscopeSectors = 8;
  bool _kaleidoscopeMirror = true;
  double _kaleidoscopeRotation = 0.0;
  int _kaleidoscopeMirrorMode =
      0; // 0=alternado, 1=doble, 2=triple, 3=sin espejo
  FractalKaleidoscopeState? _kaleidoscopeRestoreAfterForcedModule;

  bool get kaleidoscopeEnabled => _kaleidoscopeEnabled;
  int get kaleidoscopeSectors => _kaleidoscopeSectors;
  bool get kaleidoscopeMirror => _kaleidoscopeMirror;
  double get kaleidoscopeRotation => _kaleidoscopeRotation;
  int get kaleidoscopeMirrorMode => _kaleidoscopeMirrorMode;

  void setKaleidoscopeEnabled(bool enabled) {
    // Force enabled for kaleidoscope modules.
    if (FractalKaleidoscopeModulePolicy.isForcedModuleId(_module.id)) {
      enabled = true;
    }
    if (_kaleidoscopeEnabled != enabled) {
      _kaleidoscopeEnabled = enabled;
      notifyListeners();
    }
  }

  void setKaleidoscopeSectors(int sectors) {
    final clamped = sectors.clamp(4, 16);
    if (_kaleidoscopeSectors != clamped) {
      _kaleidoscopeSectors = clamped;
      notifyListeners();
    }
  }

  void setKaleidoscopeMirror(bool mirror) {
    if (_kaleidoscopeMirror != mirror) {
      _kaleidoscopeMirror = mirror;
      notifyListeners();
    }
  }

  void setKaleidoscopeMirrorMode(int mode) {
    final clamped = mode.clamp(0, 3);
    if (_kaleidoscopeMirrorMode != clamped) {
      _kaleidoscopeMirrorMode = clamped;
      notifyListeners();
    }
  }

  void setKaleidoscopeRotation(double rotation) {
    final normalized = FractalEffectInputBounds.normalizeKaleidoscopeRotation(
      candidate: rotation,
      current: _kaleidoscopeRotation,
    );
    if (_kaleidoscopeRotation != normalized) {
      _kaleidoscopeRotation = normalized;
      notifyListeners();
    }
  }

  FractalKaleidoscopeState get _kaleidoscopeState => FractalKaleidoscopeState(
        enabled: _kaleidoscopeEnabled,
        sectors: _kaleidoscopeSectors,
        mirror: _kaleidoscopeMirror,
        rotation: _kaleidoscopeRotation,
        mirrorMode: _kaleidoscopeMirrorMode,
      );

  void _setKaleidoscopeState(FractalKaleidoscopeState state) {
    _kaleidoscopeEnabled = state.enabled;
    _kaleidoscopeSectors = state.sectors;
    _kaleidoscopeMirror = state.mirror;
    _kaleidoscopeRotation = state.rotation;
    _kaleidoscopeMirrorMode = state.mirrorMode;
  }

  void _applyKaleidoscopeModulePolicy(String moduleId) {
    final transition = FractalKaleidoscopeModulePolicy.transitionForModule(
      moduleId: moduleId,
      current: _kaleidoscopeState,
      restoreAfterForcedModule: _kaleidoscopeRestoreAfterForcedModule,
    );
    _setKaleidoscopeState(transition.effective);
    _kaleidoscopeRestoreAfterForcedModule = transition.restoreAfterForcedModule;
  }

  /// Switches to a different fractal module.
  ///
  /// The [module] must be a valid module from the registry.
  /// Applies the module's default preset after switching.
  /// Triggers a smooth morph transition animation.
  ///
  /// No-op if [module] is already the current module.
  void selectModule(FractalModule module, {bool animate = true}) {
    if (_module.id == module.id) {
      return;
    }

    final previousId = _module.id;
    _module = module;
    _applyPreset(module.defaultPreset);

    if (animate) {
      _startMorphTransition(previousId);
    }

    _applyKaleidoscopeModulePolicy(module.id);

    notifyListeners();
    _logChange('stateChange', 'moduleSwitch', 'Switched to ${module.id}');
  }

  /// Starts a morph transition animation between fractal types.
  void _startMorphTransition(String fromModuleId) {
    // Skip timer-based animations in test mode
    if (_isTest) {
      _morphProgress = 1.0;
      _isMorphing = false;
      return;
    }

    _previousModuleId = fromModuleId;
    _isMorphing = true;
    _morphProgress = 0.0;

    HapticFeedback.lightImpact();

    _morphTimer?.cancel();

    const duration = Duration(milliseconds: 600);
    const fps = 60;
    final steps = (duration.inMilliseconds / (1000 / fps)).round();
    var step = 0;

    _morphTimer = Timer.periodic(
      Duration(milliseconds: 1000 ~/ fps),
      (timer) {
        step++;
        // Use ease-out cubic curve
        final t = step / steps;
        _morphProgress = 1.0 - pow(1.0 - t, 3);
        notifyListeners();

        if (step >= steps) {
          timer.cancel();
          _morphProgress = 1.0;
          _isMorphing = false;
          _previousModuleId = null;
          notifyListeners();
        }
      },
    );
  }

  /// Updates a single fractal parameter.
  ///
  /// The [id] must match a parameter defined in the current module.
  /// The [value] is automatically clamped to the parameter's valid range.
  ///
  /// Example:
  /// ```dart
  /// controller.updateParam('iterations', 200);
  /// controller.updateParam('colorScheme', 2);
  /// ```
  void updateParam(String id, Object value) {
    final schema = _findParam(id);
    if (schema == null) return;
    _params = Map<String, Object>.from(_params);
    _params[id] = normalizeFractalParamValue(schema, value);
    notifyListeners();
    _logChange('stateChange', 'paramUpdate', 'Updated $id',
        metadata: {'value': value.toString()});
  }

  /// Applies a preset, setting all parameters and view state.
  ///
  /// The [preset] should match the current module (by moduleId).
  /// Missing parameters are filled with module defaults.
  void applyPreset(FractalPreset preset) {
    _applyPreset(preset);
    notifyListeners();
    _logChange('stateChange', 'presetApply', 'Applied preset ${preset.name}');
  }

  /// Resets all parameters to the module's default values.
  ///
  /// Does not affect the view state (pan, zoom, rotation).
  void resetParams() {
    _params = _normalizedParamsForPreset(_module.defaultPreset);
    notifyListeners();
    _logChange('stateChange', 'reset', 'Reset params to default');
  }

  /// Resets the view state to initial values.
  ///
  /// Sets zoom to 1.0, pan to center, and rotation to zero.
  /// Does not affect fractal parameters.
  void resetView() {
    _view = FractalViewState.initial();
    _lastAdaptiveZoom = _view.zoom;
    notifyListeners();
    _logChange('stateChange', 'reset', 'Reset view');
  }

  /// Resets the entire session state.
  ///
  /// Restores parameters to defaults, resets view state,
  /// and disables transparent background. The selected module
  /// remains unchanged.
  void resetSession() {
    // Reset params to module defaults, but reset the view to the true "initial" view.
    // (Module default presets may intentionally start at a non-zero pan like -0.5,0.0 for Mandelbrot.)
    _applyPreset(_module.defaultPreset);
    _view = FractalViewState.initial();
    _lastAdaptiveZoom = _view.zoom;
    _transparentBackground = false;
    _rotationLocked = false;
    notifyListeners();
    _logChange('stateChange', 'reset', 'Reset session');
  }

  /// Randomizes all parameters within their valid ranges.
  ///
  /// Creates interesting, unpredictable fractal configurations.
  /// Useful for exploration and discovery.
  void randomizeParams() {
    final random = Random();
    _params = {
      for (final param in _module.parameters)
        param.id: randomFractalParamValue(param, random),
    };
    notifyListeners();
    _logChange(
        'stateChange', 'randomize', 'Randomized params for ${_module.id}');
  }

  /// Updates the zoom level.
  ///
  /// The [zoom] value is clamped to range [moduleMinZoom, 1e12] to support
  /// deep-zoom exploration before precision fallback kicks in.
  void updateZoom(double zoom) {
    final clampedZoom = FractalViewInputBounds.normalizeZoom(
      candidate: zoom,
      currentZoom: _view.zoom,
      moduleId: _module.id,
    );
    final zoomingIn = clampedZoom > (_lastAdaptiveZoom * _adaptiveZoomEpsilon);
    _view = _view.copyWith(zoom: clampedZoom);
    _lastAdaptiveZoom = clampedZoom;

    final autoIterations = _applyAdaptiveIterationsForZoom(
      zoom: clampedZoom,
      zoomingIn: zoomingIn,
    );

    notifyListeners();
    _logChange('userAction', 'zoom', 'Zoom updated', metadata: {
      'zoom': clampedZoom,
      if (autoIterations != null) 'autoIterations': autoIterations,
    });
  }

  /// Updates the 2D pan offset.
  ///
  /// Each component of [pan] is clamped to range [-3.0, 3.0].
  /// Used for 2D fractals to navigate the complex plane.
  void updatePan(Vector2 pan) {
    _view = _view.copyWith(
      pan: Vector2(
        FractalViewInputBounds.normalizePanComponent(
          candidate: pan.x,
          current: _view.pan.x,
        ),
        FractalViewInputBounds.normalizePanComponent(
          candidate: pan.y,
          current: _view.pan.y,
        ),
      ),
    );
    notifyListeners();
    _logChange('userAction', 'pan', 'Pan updated',
        metadata: {'x': pan.x, 'y': pan.y});
  }

  /// Updates the 3D rotation angles.
  ///
  /// Used for 3D fractals like Mandelbulb to control camera orientation.
  void updateRotation(Vector3 rotation) {
    _view = _view.copyWith(
      rotation: FractalViewInputBounds.normalizeRotation(
        candidate: rotation,
        current: _view.rotation,
      ),
    );
    notifyListeners();
  }

  /// Locks or unlocks gesture-based rotation.
  void setRotationLocked(bool value) {
    if (_rotationLocked == value) return;
    _rotationLocked = value;
    notifyListeners();
    _logChange(
      'stateChange',
      'rotationLock',
      value ? 'Rotation locked' : 'Rotation unlocked',
    );
  }

  /// Toggles gesture-based rotation lock.
  void toggleRotationLock() {
    setRotationLocked(!_rotationLocked);
  }

  void setGlowEnabled(bool value) {
    if (_glowEnabled == value) return;
    _glowEnabled = value;
    notifyListeners();
  }

  void setGlowSigma(double value) {
    _glowSigma = FractalEffectInputBounds.normalizeGlowSigma(
      candidate: value,
      current: _glowSigma,
    );
    notifyListeners();
  }

  void setGlowIntensity(double value) {
    _glowIntensity = FractalEffectInputBounds.normalizeGlowIntensity(
      candidate: value,
      current: _glowIntensity,
    );
    notifyListeners();
  }

  /// Sets whether the background should be transparent.
  ///
  /// When [value] is true, the shader renders background pixels
  /// with alpha=0, suitable for transparent PNG export.
  void setTransparentBackground(bool value) {
    _transparentBackground = value;
    notifyListeners();
  }

  void _logChange(String type, String category, String message,
      {Map<String, dynamic>? metadata}) {
    _logger?.log(LogEvent(
      timestamp: DateTime.now(),
      type: type,
      category: category,
      message: message,
      metadata: metadata,
    ));
  }

  /// Records finding an interesting spot in the fractal.
  ///
  /// When multiple interesting spots are found in quick succession,
  /// triggers a celebration effect.
  void recordInterestingSpot() {
    final now = DateTime.now();

    if (_lastInterestingSpotTime != null) {
      final elapsed = now.difference(_lastInterestingSpotTime!);
      if (elapsed.inSeconds < 30) {
        _consecutiveInterestingSpots++;

        // Trigger celebration after finding 3 interesting spots quickly
        if (_consecutiveInterestingSpots >= 3) {
          celebrate();
          _consecutiveInterestingSpots = 0;
        }
      } else {
        _consecutiveInterestingSpots = 1;
      }
    } else {
      _consecutiveInterestingSpots = 1;
    }

    _lastInterestingSpotTime = now;
    _logChange('userAction', 'discovery', 'Found interesting spot');
  }

  /// Manually triggers a celebration effect.
  void celebrate() {
    if (_isCelebrating) return;

    _isCelebrating = true;
    if (!_isTest) {
      HapticFeedback.mediumImpact();
    }
    _celebrationController.add(null);
    notifyListeners();

    // Skip timer in test mode
    if (_isTest) {
      _isCelebrating = false;
      return;
    }

    _celebrationTimer?.cancel();
    _celebrationTimer = Timer(const Duration(milliseconds: 2500), () {
      _isCelebrating = false;
      notifyListeners();
    });

    _logChange('event', 'celebration', 'Celebration triggered');
  }

  @override
  void dispose() {
    _morphTimer?.cancel();
    _celebrationTimer?.cancel();
    _celebrationController.close();
    super.dispose();
  }

  void _applyPreset(FractalPreset preset) {
    _params = _normalizedParamsForPreset(preset);
    _applyPresetView(preset.view);
  }

  Map<String, Object> _normalizedParamsForPreset(FractalPreset preset) {
    final defaults = <String, Object>{
      for (final param in _module.parameters) param.id: param.defaultValue,
    };

    final merged = {
      ...defaults,
      ...preset.params,
    };

    final clamped = <String, Object>{};
    for (final param in _module.parameters) {
      clamped[param.id] = normalizeFractalParamValue(
        param,
        merged[param.id] ?? param.defaultValue,
      );
    }
    return clamped;
  }

  void _applyPresetView(FractalViewState view) {
    _view = FractalViewInputBounds.normalizeView(
      candidate: view,
      current: _view,
      moduleId: _module.id,
    );
    _lastAdaptiveZoom = _view.zoom;
  }

  int? _applyAdaptiveIterationsForZoom({
    required double zoom,
    required bool zoomingIn,
  }) {
    if (!_adaptiveIterationsEnabled || !zoomingIn) {
      return null;
    }
    if (_module.dimension != FractalDimension.twoD) {
      return null;
    }

    final iterationsSchema = _findParam('iterations');
    if (iterationsSchema == null ||
        iterationsSchema.type != FractalParamType.integer) {
      return null;
    }

    final minIterations = iterationsSchema.min.round();
    final maxIterations = iterationsSchema.max.round();
    final currentValue = _params['iterations'];
    final currentIterations = currentValue is num
        ? currentValue.round()
        : (iterationsSchema.defaultValue as num).round();
    final baseIterations = (iterationsSchema.defaultValue as num).round();

    final targetIterations = _suggestIterationsForZoom(
      zoom: zoom,
      baseIterations: baseIterations,
      minIterations: minIterations,
      maxIterations: maxIterations,
    );
    if (targetIterations <= currentIterations) {
      return null;
    }

    final delta = targetIterations - currentIterations;
    final step = delta >= 256
        ? 64
        : delta >= 96
            ? 32
            : delta >= 32
                ? 16
                : _adaptiveIterationsMinStep;
    final nextIterations =
        (currentIterations + step).clamp(minIterations, maxIterations);
    if (nextIterations <= currentIterations) {
      return null;
    }

    _params = Map<String, Object>.from(_params);
    _params['iterations'] = nextIterations;
    _logChange(
      'stateChange',
      'adaptiveIterations',
      'Adaptive iterations increased',
      metadata: {
        'module': _module.id,
        'zoom': zoom,
        'from': currentIterations,
        'to': nextIterations,
        'target': targetIterations,
      },
    );
    return nextIterations;
  }

  int _suggestIterationsForZoom({
    required double zoom,
    required int baseIterations,
    required int minIterations,
    required int maxIterations,
  }) {
    final safeZoom = max(1.0, zoom);
    final zoomOctaves = log(safeZoom) / ln2;
    final extra = max(0, (zoomOctaves * 48.0).round());
    final raw = baseIterations + extra;
    // Snap to a small step to avoid jittery one-by-one jumps.
    final snapped = ((raw + 3) ~/ 4) * 4;
    return snapped.clamp(minIterations, maxIterations);
  }

  FractalParameter? _findParam(String id) {
    for (final param in _module.parameters) {
      if (param.id == id) {
        return param;
      }
    }
    return null;
  }

  /// Alias for [view] for backward compatibility.
  FractalViewState get viewState => view;

  /// The currently selected fractal module (alias for [module]).
  FractalModule get currentModule => _module;

  /// Loads a complete state from another controller or snapshot.
  ///
  /// This initializes the controller from a full state including
  /// module, parameters, view state, and transparency setting.
  /// Parameters are clamped to the target module's schema.
  ///
  /// Can accept either a [module] object directly or a [moduleId] string.
  void loadState({
    FractalModule? module,
    String? moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
    bool transparentBackground = false,
    bool animateModule = false,
  }) {
    // Find the module by ID or use provided module
    final FractalModule targetModule;
    if (module != null) {
      targetModule = module;
    } else if (moduleId != null) {
      targetModule = registry.modules.firstWhere(
        (m) => m.id == moduleId,
        orElse: () => _module,
      );
    } else {
      targetModule = _module;
    }

    // Switch to the target module
    if (targetModule.id != _module.id) {
      if (animateModule) {
        selectModule(targetModule, animate: true);
      } else {
        _module = targetModule;
      }
    }

    _applyKaleidoscopeModulePolicy(_module.id);

    // Apply parameters with clamping
    final clamped = <String, Object>{};
    for (final param in _module.parameters) {
      final value = params[param.id] ?? param.defaultValue;
      clamped[param.id] = normalizeFractalParamValue(param, value);
    }
    _params = clamped;

    // Set view state
    _view = FractalViewInputBounds.normalizeView(
      candidate: view,
      current: _view,
      moduleId: _module.id,
    );
    _lastAdaptiveZoom = _view.zoom;

    // Set transparency
    _transparentBackground = transparentBackground;

    notifyListeners();
    _logChange('stateChange', 'loadState', 'Loaded state for ${_module.id}');
  }
}

import 'dart:math';

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_value_normalizer.dart';

/// Generates one randomized value for a fractal parameter schema.
///
/// This pure helper keeps the controller's randomization data flow visible and
/// replayable in tests without depending on FractalController state. Returned
/// values are normalized through the same schema contract used for presets,
/// replayed state, and direct UI updates.
Object randomFractalParamValue(FractalParameter param, Random random) {
  switch (param.type) {
    case FractalParamType.float:
      final raw = param.min + random.nextDouble() * (param.max - param.min);
      return normalizeFractalParamValue(
        param,
        roundFractalParamValueToStep(raw, param.step),
      );
    case FractalParamType.integer:
      final bounds = FractalNumericParamBounds.fromSchema(param);
      assert(
        bounds.containsInteger,
        'integer parameter bounds must include at least one integer value',
      );
      if (!bounds.containsInteger) {
        return normalizeFractalParamValue(param, param.defaultValue);
      }
      final min = bounds.min.ceil();
      final max = bounds.max.floor();
      return normalizeFractalParamValue(
        param,
        min + random.nextInt(max - min + 1),
      );
    case FractalParamType.enumeration:
      if (param.options.isNotEmpty) {
        final choice = param.options[random.nextInt(param.options.length)];
        return choice.value;
      }
      return param.defaultValue;
    case FractalParamType.boolean:
      return random.nextBool();
  }
}

/// Replayable decision for snapping a randomized float to slider precision.
///
/// Parameter schemas are hand-authored across a large catalog. A malformed
/// non-finite step or raw value must not crash randomization before the shared
/// schema normalizer gets a chance to clamp/fallback the value.
final class FractalParamStepSnapPlan {
  final double inputValue;
  final double step;
  final double value;
  final bool appliedStep;

  const FractalParamStepSnapPlan._({
    required this.inputValue,
    required this.step,
    required this.value,
    required this.appliedStep,
  });

  factory FractalParamStepSnapPlan.fromValue({
    required double value,
    required double step,
  }) {
    if (!value.isFinite || !step.isFinite || step <= 0.0) {
      return FractalParamStepSnapPlan._(
        inputValue: value,
        step: step,
        value: value,
        appliedStep: false,
      );
    }

    final snapped = (value / step).round() * step;
    if (!snapped.isFinite) {
      return FractalParamStepSnapPlan._(
        inputValue: value,
        step: step,
        value: value,
        appliedStep: false,
      );
    }

    return FractalParamStepSnapPlan._(
      inputValue: value,
      step: step,
      value: double.parse(snapped.toStringAsFixed(6)),
      appliedStep: true,
    );
  }
}

/// Snaps float randomization to slider step precision while avoiding typical
/// binary floating-point display noise.
double roundFractalParamValueToStep(double value, double step) {
  return FractalParamStepSnapPlan.fromValue(value: value, step: step).value;
}

/// Pure bounds for effect inputs accepted by [FractalController].
///
/// Glow values are bounded shader-control inputs: finite values and infinities
/// clamp to explicit UI limits, while NaN falls back to the last known-good
/// value instead of being promoted to a maximum by [double.clamp].
/// Kaleidoscope rotation is intentionally unbounded, but shader uniforms still
/// need finite angles, so non-finite candidates preserve the last finite angle.
final class FractalEffectInputBounds {
  static const double minGlowSigma = 0.1;
  static const double maxGlowSigma = 5.0;
  static const double minGlowIntensity = 0.0;
  static const double maxGlowIntensity = 1.0;

  const FractalEffectInputBounds._();

  static double normalizeGlowSigma({
    required double candidate,
    required double current,
  }) {
    return _normalizeBounded(
      candidate: candidate,
      current: current,
      minValue: minGlowSigma,
      maxValue: maxGlowSigma,
    );
  }

  static double normalizeGlowIntensity({
    required double candidate,
    required double current,
  }) {
    return _normalizeBounded(
      candidate: candidate,
      current: current,
      minValue: minGlowIntensity,
      maxValue: maxGlowIntensity,
    );
  }

  static double normalizeKaleidoscopeRotation({
    required double candidate,
    required double current,
  }) {
    if (candidate.isFinite) return candidate;
    return current.isFinite ? current : 0.0;
  }

  static double _normalizeBounded({
    required double candidate,
    required double current,
    required double minValue,
    required double maxValue,
  }) {
    final fallback = current.isNaN ? minValue : current;
    if (candidate.isNaN) {
      return fallback.clamp(minValue, maxValue).toDouble();
    }
    return candidate.clamp(minValue, maxValue).toDouble();
  }
}

import 'package:flutter_fractals/features/renderer/providers/fractal_effect_input_bounds.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('FractalEffectInputBounds', () {
    test('preserves current bounded effect values when candidate is NaN', () {
      expect(
        FractalEffectInputBounds.normalizeGlowSigma(
          candidate: double.nan,
          current: 2.5,
        ),
        2.5,
      );
      expect(
        FractalEffectInputBounds.normalizeGlowIntensity(
          candidate: double.nan,
          current: 0.6,
        ),
        0.6,
      );
    });

    test('clamps finite and infinite bounded effect values', () {
      expect(
        FractalEffectInputBounds.normalizeGlowSigma(
          candidate: double.negativeInfinity,
          current: 2.5,
        ),
        FractalEffectInputBounds.minGlowSigma,
      );
      expect(
        FractalEffectInputBounds.normalizeGlowSigma(
          candidate: double.infinity,
          current: 2.5,
        ),
        FractalEffectInputBounds.maxGlowSigma,
      );
      expect(
        FractalEffectInputBounds.normalizeGlowIntensity(
          candidate: -0.5,
          current: 0.6,
        ),
        FractalEffectInputBounds.minGlowIntensity,
      );
      expect(
        FractalEffectInputBounds.normalizeGlowIntensity(
          candidate: 2.0,
          current: 0.6,
        ),
        FractalEffectInputBounds.maxGlowIntensity,
      );
    });

    test('preserves finite kaleidoscope rotation for non-finite candidates',
        () {
      expect(
        FractalEffectInputBounds.normalizeKaleidoscopeRotation(
          candidate: double.nan,
          current: 0.75,
        ),
        0.75,
      );
      expect(
        FractalEffectInputBounds.normalizeKaleidoscopeRotation(
          candidate: double.infinity,
          current: 0.75,
        ),
        0.75,
      );
    });
  });
}

import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Pure bounds for gesture/view input accepted by FractalController.
///
/// Dart's [double.clamp] treats NaN as the upper bound. Gesture telemetry and
/// replayed state can occasionally contain NaN, and promoting that to max zoom
/// or max pan makes failures hard to replay. Preserve the last known-good value
/// for NaN while still clamping infinities to the explicit viewport limits.
/// Rotation has no explicit UI bounds, but shader uniforms still require finite
/// values; non-finite rotation components fall back to last known-good angles.
final class FractalViewInputBounds {
  static const double maxZoom = 1e12;
  static const double defaultMinZoom = 1e-9;
  static const double cantorSetMinZoom = 0.2;
  static const double minPan = -3.0;
  static const double maxPan = 3.0;

  const FractalViewInputBounds._();

  static double minZoomForModule(String moduleId) {
    switch (moduleId) {
      case 'cantor_set':
        // Prevent ultra-zoomed-out aliasing that appears as black vertical bands.
        return cantorSetMinZoom;
      default:
        return defaultMinZoom;
    }
  }

  static double normalizeZoom({
    required double candidate,
    required double currentZoom,
    required String moduleId,
  }) {
    final minZoom = minZoomForModule(moduleId);
    final fallback = currentZoom.isNaN ? minZoom : currentZoom;
    if (candidate.isNaN) return fallback.clamp(minZoom, maxZoom).toDouble();
    return candidate.clamp(minZoom, maxZoom).toDouble();
  }

  static double normalizePanComponent({
    required double candidate,
    required double current,
  }) {
    final fallback = current.isNaN ? 0.0 : current;
    if (candidate.isNaN) return fallback.clamp(minPan, maxPan).toDouble();
    return candidate.clamp(minPan, maxPan).toDouble();
  }

  static double normalizeRotationComponent({
    required double candidate,
    required double current,
  }) {
    if (candidate.isFinite) return candidate;
    return current.isFinite ? current : 0.0;
  }

  static Vector3 normalizeRotation({
    required Vector3 candidate,
    required Vector3 current,
  }) {
    return Vector3(
      normalizeRotationComponent(candidate: candidate.x, current: current.x),
      normalizeRotationComponent(candidate: candidate.y, current: current.y),
      normalizeRotationComponent(candidate: candidate.z, current: current.z),
    );
  }

  /// Sanitizes externally supplied view snapshots before they become controller
  /// state. Finite values preserve existing behavior; NaN values fall back to
  /// the last known-good view while infinities clamp to explicit bounds or, for
  /// unbounded rotation, fall back to the last known-good finite angle.
  static FractalViewState normalizeView({
    required FractalViewState candidate,
    required FractalViewState current,
    required String moduleId,
  }) {
    return candidate.copyWith(
      pan: Vector2(
        normalizePanComponent(
            candidate: candidate.pan.x, current: current.pan.x),
        normalizePanComponent(
            candidate: candidate.pan.y, current: current.pan.y),
      ),
      zoom: normalizeZoom(
        candidate: candidate.zoom,
        currentZoom: current.zoom,
        moduleId: moduleId,
      ),
      rotation: normalizeRotation(
        candidate: candidate.rotation,
        current: current.rotation,
      ),
    );
  }
}

import 'dart:io';

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';

const bool kForceCpuFallback =
    bool.fromEnvironment('FORCE_CPU_FALLBACK', defaultValue: false);
// Android emulator GPU is allowed in auto mode. Runtime health probes in
// FractalViewerScreen enforce fast fallback to CPU on invalid output.

enum RendererBackend { gpu, cpu }

enum FallbackReasonCode {
  none,
  forcedByFlag,
  androidEmulator,
  gpuHealthCheckFailed,
  deepZoomPrecision,
  manualToggle,
  moduleUnsupported,
}

class BackendDecision {
  final RendererBackend backend;
  final FallbackReasonCode reasonCode;
  final String detail;

  const BackendDecision({
    required this.backend,
    required this.reasonCode,
    required this.detail,
  });

  bool get isFallback => backend == RendererBackend.cpu;

  String get reasonToken {
    switch (reasonCode) {
      case FallbackReasonCode.none:
        return 'none';
      case FallbackReasonCode.forcedByFlag:
        return 'forced_by_flag';
      case FallbackReasonCode.androidEmulator:
        return 'android_emulator';
      case FallbackReasonCode.gpuHealthCheckFailed:
        return 'gpu_health_check_failed';
      case FallbackReasonCode.deepZoomPrecision:
        return 'deep_zoom_precision';
      case FallbackReasonCode.manualToggle:
        return 'manual_toggle';
      case FallbackReasonCode.moduleUnsupported:
        return 'module_unsupported';
    }
  }

  String toLogLine({required String moduleId}) {
    return '[renderer] backend_decision backend=${backend.name} reason=$reasonToken module=$moduleId detail=$detail';
  }

  String toUserStatusText() {
    if (!isFallback) return 'Renderer: GPU';
    switch (reasonCode) {
      case FallbackReasonCode.androidEmulator:
        return 'Using stable renderer for this Android emulator';
      case FallbackReasonCode.gpuHealthCheckFailed:
        return 'GPU output unavailable, using stable renderer';
      case FallbackReasonCode.deepZoomPrecision:
        return 'Deep zoom precision mode enabled';
      case FallbackReasonCode.manualToggle:
        return 'Renderer preference applied';
      case FallbackReasonCode.moduleUnsupported:
        return 'Stable renderer enabled for this fractal mode';
      case FallbackReasonCode.forcedByFlag:
        return 'Stable renderer forced by launch flag';
      case FallbackReasonCode.none:
        return 'Renderer: CPU';
    }
  }
}

class BackendPolicyInput {
  final bool isAndroid;
  final bool isWeb;
  final bool isEmulator;
  final RendererBackendMode userMode;
  final bool gpuHealthFailed;
  final bool deepZoomNeedsCpu;
  final FractalDimension dimension;

  const BackendPolicyInput({
    required this.isAndroid,
    required this.isWeb,
    required this.isEmulator,
    required this.userMode,
    required this.gpuHealthFailed,
    required this.deepZoomNeedsCpu,
    required this.dimension,
  });
}

/// Replayable explanation for the backend rule selected by the policy.
///
/// Platform probes are currently advisory in auto mode: Android emulator status
/// is logged and passed through, but runtime health checks decide fallback.
/// Keeping the selected rule visible makes that precedence testable instead of
/// hiding it in early returns.
class BackendPolicyResolution {
  final BackendDecision decision;
  final String selectedRule;
  final bool platformSignalsUsed;

  const BackendPolicyResolution({
    required this.decision,
    required this.selectedRule,
    required this.platformSignalsUsed,
  });
}

class RendererBackendPolicy {
  const RendererBackendPolicy();

  BackendDecision decide(BackendPolicyInput input) => explain(input).decision;

  BackendPolicyResolution explain(BackendPolicyInput input) {
    if (kForceCpuFallback) {
      return const BackendPolicyResolution(
        selectedRule: 'force_cpu_flag',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.forcedByFlag,
          detail: 'FORCE_CPU_FALLBACK=true',
        ),
      );
    }

    if (input.dimension != FractalDimension.twoD) {
      // 3D modules (e.g. Mandelbulb/Mandelbox) currently rely on GPU shader
      // rendering. Forcing CPU here only produces a disabled placeholder pane.
      // Keep these modules on GPU by default.
      if (input.userMode == RendererBackendMode.cpuOnly) {
        return const BackendPolicyResolution(
          selectedRule: 'gpu_required_module_cpu_only_ignored',
          platformSignalsUsed: false,
          decision: BackendDecision(
            backend: RendererBackend.gpu,
            reasonCode: FallbackReasonCode.moduleUnsupported,
            detail: 'cpu_only_ignored_for_3d_gpu_required',
          ),
        );
      }
      return const BackendPolicyResolution(
        selectedRule: 'gpu_required_module',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.gpu,
          reasonCode: FallbackReasonCode.none,
          detail: '3d_gpu_path',
        ),
      );
    }

    if (input.userMode == RendererBackendMode.cpuOnly) {
      return const BackendPolicyResolution(
        selectedRule: 'manual_cpu_only',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.manualToggle,
          detail: 'cpu_only',
        ),
      );
    }

    if (input.userMode == RendererBackendMode.gpuOnly) {
      return const BackendPolicyResolution(
        selectedRule: 'manual_gpu_only',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.gpu,
          reasonCode: FallbackReasonCode.manualToggle,
          detail: 'gpu_only',
        ),
      );
    }

    // Emulator targets are handled like physical devices in auto mode.
    // Runtime GPU health checks own fallback decisions.

    if (input.gpuHealthFailed) {
      return const BackendPolicyResolution(
        selectedRule: 'gpu_health_failed',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.gpuHealthCheckFailed,
          detail: 'frame_probe_detected_invalid_gpu_output',
        ),
      );
    }

    if (input.deepZoomNeedsCpu) {
      return const BackendPolicyResolution(
        selectedRule: 'deep_zoom_precision',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.deepZoomPrecision,
          detail: 'deep_zoom_precision_policy',
        ),
      );
    }

    return const BackendPolicyResolution(
      selectedRule: 'healthy_gpu_target',
      platformSignalsUsed: false,
      decision: BackendDecision(
        backend: RendererBackend.gpu,
        reasonCode: FallbackReasonCode.none,
        detail: 'healthy_gpu_target',
      ),
    );
  }
}

/// Replayable Android emulator signal snapshot.
///
/// Device probing is intentionally best-effort and IO-heavy; keeping the
/// signal classifier pure makes marker drift testable without touching
/// `/proc`, `getprop`, or `/system` in unit tests.
class AndroidEmulatorSignals {
  final String cpuInfo;
  final String hardware;
  final String buildCharacteristics;
  final String productModel;
  final String buildProp;

  const AndroidEmulatorSignals({
    this.cpuInfo = '',
    this.hardware = '',
    this.buildCharacteristics = '',
    this.productModel = '',
    this.buildProp = '',
  });

  bool get isEmulator =>
      AndroidEmulatorMarkerCatalog.hasCpuInfoMarker(cpuInfo) ||
      AndroidEmulatorMarkerCatalog.hasHardwareMarker(hardware) ||
      AndroidEmulatorMarkerCatalog.hasBuildCharacteristicsMarker(
        buildCharacteristics,
      ) ||
      AndroidEmulatorMarkerCatalog.hasProductModelMarker(productModel) ||
      AndroidEmulatorMarkerCatalog.hasBuildPropMarker(buildProp);
}

/// Named emulator marker contract used by Android emulator signal detection.
///
/// The markers are intentionally conservative: substring checks are used only
/// for fields that can contain labels or full property files, while the direct
/// `ro.hardware` value must match a known virtual hardware token exactly.
class AndroidEmulatorMarkerCatalog {
  static const List<String> cpuInfoSubstrings = [
    'ranchu',
    'goldfish',
    'qemu',
    'android virtual processor',
  ];
  static const List<String> exactHardwareValues = ['ranchu', 'goldfish'];
  static const List<String> buildCharacteristicsSubstrings = ['emulator'];
  static const List<String> productModelSubstrings = [
    'sdk_gphone',
    'android sdk built for',
  ];
  static const List<String> buildPropSubstrings = [
    'ro.hardware=goldfish',
    'ro.hardware=ranchu',
    'sdk_gphone',
    'generic_x86',
  ];

  const AndroidEmulatorMarkerCatalog._();

  static bool hasCpuInfoMarker(String value) {
    return _containsAny(value, cpuInfoSubstrings);
  }

  static bool hasHardwareMarker(String value) {
    return exactHardwareValues.contains(value.trim().toLowerCase());
  }

  static bool hasBuildCharacteristicsMarker(String value) {
    return _containsAny(value, buildCharacteristicsSubstrings);
  }

  static bool hasProductModelMarker(String value) {
    return _containsAny(value, productModelSubstrings);
  }

  static bool hasBuildPropMarker(String value) {
    return _containsAny(value, buildPropSubstrings);
  }

  static bool _containsAny(String value, List<String> markers) {
    final normalized = value.toLowerCase();
    return markers.any(normalized.contains);
  }
}

Future<bool> detectAndroidEmulator() async {
  if (kIsWeb || !Platform.isAndroid) return false;

  var signals = const AndroidEmulatorSignals();

  // 1. /proc/cpuinfo — check for emulator markers
  try {
    signals = AndroidEmulatorSignals(
      cpuInfo: await File('/proc/cpuinfo').readAsString(),
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  // 2. getprop — most reliable on modern emulators
  try {
    final result = await Process.run('getprop', ['ro.hardware']);
    signals = AndroidEmulatorSignals(hardware: result.stdout as String);
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  try {
    final result = await Process.run('getprop', ['ro.build.characteristics']);
    signals = AndroidEmulatorSignals(
      buildCharacteristics: result.stdout as String,
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  try {
    final result = await Process.run('getprop', ['ro.product.model']);
    signals = AndroidEmulatorSignals(productModel: result.stdout as String);
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  // 3. /system/build.prop — fallback file check
  try {
    signals = AndroidEmulatorSignals(
      buildProp: await File('/system/build.prop').readAsString(),
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  return false;
}

import 'dart:math' as math;

import 'package:flutter/foundation.dart';

const double _mandelbrotDf2LowerThreshold = 5e6;
const double _mandelbrotDf2UpperThreshold = 1e12;
const double _escapeTimeCpuFallbackThreshold = 1e9;
const double _defaultCpuFallbackThreshold = 1e7;

/// Describes the precision boundaries for one fractal module.
@immutable
class DeepZoomThresholds {
  final double cpuFallbackZoom;
  final double? doubleFloatLowerZoom;
  final double? doubleFloatUpperZoom;

  const DeepZoomThresholds({
    required this.cpuFallbackZoom,
    this.doubleFloatLowerZoom,
    this.doubleFloatUpperZoom,
  })  : assert(
          (doubleFloatLowerZoom == null) == (doubleFloatUpperZoom == null),
          'double-float ranges must provide both lower and upper bounds',
        ),
        assert(
          (doubleFloatLowerZoom ?? double.negativeInfinity) <
              (doubleFloatUpperZoom ?? double.infinity),
          'double-float lower bound must be below upper bound',
        ),
        assert(
          (doubleFloatUpperZoom ?? double.negativeInfinity) <= cpuFallbackZoom,
          'double-float range must end no later than CPU fallback',
        );

  bool get supportsDoubleFloat => doubleFloatLowerZoom != null;

  bool shouldUseCpuFallback(double zoom) => zoom >= cpuFallbackZoom;

  bool shouldUseDoubleFloat(double zoom) {
    final lower = doubleFloatLowerZoom;
    final upper = doubleFloatUpperZoom;
    if (lower == null || upper == null) return false;
    return zoom >= lower && zoom < upper;
  }
}

/// Replayable precision routing decision for a module/zoom sample.
///
/// Renderer code needs CPU fallback and double-float eligibility to agree on
/// the same threshold snapshot. Keeping both booleans with their source
/// thresholds exposes that data-flow instead of recomputing partial decisions
/// at separate call sites.
@immutable
class DeepZoomPrecisionDecision {
  final String moduleId;
  final double zoom;
  final DeepZoomThresholds thresholds;

  const DeepZoomPrecisionDecision({
    required this.moduleId,
    required this.zoom,
    required this.thresholds,
  });

  bool get shouldUseCpuFallback => thresholds.shouldUseCpuFallback(zoom);
  bool get shouldUseDoubleFloat => thresholds.shouldUseDoubleFloat(zoom);
  double get cpuFallbackZoom => thresholds.cpuFallbackZoom;
}

/// Decides when GPU precision is likely insufficient at deep zoom.
///
/// ## Float32 precision analysis
///
/// GPU fragment shaders use float32 arithmetic (~7 significant digits,
/// mantissa ≈ 2^-24 ≈ 6e-8).
///
/// The coordinate span per pixel is: span_per_px = fractal_range / (zoom * resolution)
///   For a 1080p display and a fractal range of ~3 units:
///     span_per_px = 3 / (zoom * 1920) ≈ 1.6e-3 / zoom
///
/// Float32 artifacts appear when the per-pixel span drops below the
/// representable precision at the current center offset. In the worst case
/// (center near origin, no cancellation) this is roughly:
///     artifact threshold zoom ≈ 1.6e-3 / 6e-8 ≈ 2.7e4  ... but only at
///     an offset of ~1.0 unit from origin. Deep in the Mandelbrot boundary
///     where |c| ≈ 2, precision is consumed faster (≈ 1e4–1e5).
///     With the standard center at (0,0) or a well-normalized fractal,
///     artifacts are not visible until zoom ≈ 1e6–1e8.
///
/// Our shaders perform double-width emulation via paired float32 values
/// (see shader uniform layout) for a subset of fractals, extending usable
/// GPU range to ~1e12 before requiring CPU.
///
/// ## Conservative threshold policy
///
/// These thresholds are intentionally HIGH so GPU is used as long as
/// possible. The CPU fallback is a correctness escape hatch, not a
/// performance choice — it is significantly slower and disables GPU effects.
///
/// Raise these thresholds if you observe visible precision artifacts before
/// the switch; lower them only if tested on a low-DPI device where artifacts
/// appear earlier.
@immutable
class DeepZoomPrecisionPolicy {
  /// Maximum iterations we send to GPU shaders for real-time rendering.
  ///
  /// Most escape-time shaders clamp around this value already; keeping the
  /// cap centralized avoids overdriving slower devices at extreme zoom.
  static const int gpuMaxIterations = 2000;

  /// Per-module GPU→CPU fallback thresholds.
  ///
  /// For mandelbrot, the CPU fallback threshold is pushed to the df2 upper
  /// bound because the double-float shader [mandelbrot_df2.frag] covers the
  /// intermediate zoom range before CPU fallback.
  ///
  /// Other escape-time fractals still use float32 GPU up to their threshold,
  /// then fall back to CPU (no df2 variant available yet).
  static const Map<String, DeepZoomThresholds> _moduleThresholds = {
    // Mandelbrot: df2 shader covers zoom [5e6, 1e12), so CPU fallback only
    // kicks in at 1e12 (the df2 upper bound).
    'mandelbrot': DeepZoomThresholds(
      cpuFallbackZoom: _mandelbrotDf2UpperThreshold,
      doubleFloatLowerZoom: _mandelbrotDf2LowerThreshold,
      doubleFloatUpperZoom: _mandelbrotDf2UpperThreshold,
    ),
    // Julia & related escape-time fractals: GPU precision degrades sooner,
    // so switch to CPU around ~1e9.
    'julia': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'celtic': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'buffalo': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'burning_ship': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'tricorn': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot3': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot4': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot5': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'phoenix': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
  };

  /// Default threshold for any fractal type not listed above.
  /// Simple orbit fractals and non-escape-time types lose precision more
  /// slowly; 1e7 is a conservative upper bound for float32 at 1080p.
  static const DeepZoomThresholds _defaultThresholds = DeepZoomThresholds(
    cpuFallbackZoom: _defaultCpuFallbackThreshold,
  );

  /// Number of consecutive evaluations above the zoom threshold required
  /// before committing to CPU fallback. Prevents rapid GPU↔CPU flicker
  /// when zooming near the boundary.
  static const int _hysteresisFrames = 2;

  const DeepZoomPrecisionPolicy();

  /// Returns true when GPU precision is insufficient at the given zoom.
  ///
  /// Pure, stateless evaluation — callers that want hysteresis should
  /// use [DeepZoomHysteresis] to track frame counts.
  bool shouldUseCpuFallback({
    required String moduleId,
    required double zoom,
  }) {
    return decisionFor(moduleId: moduleId, zoom: zoom).shouldUseCpuFallback;
  }

  DeepZoomThresholds thresholdsFor(String moduleId) =>
      _moduleThresholds[moduleId] ?? _defaultThresholds;

  DeepZoomPrecisionDecision decisionFor({
    required String moduleId,
    required double zoom,
  }) {
    return DeepZoomPrecisionDecision(
      moduleId: moduleId,
      zoom: zoom,
      thresholds: thresholdsFor(moduleId),
    );
  }

  double thresholdFor(String moduleId) =>
      thresholdsFor(moduleId).cpuFallbackZoom;

  /// Returns true when the double-float shader should be used for [moduleId].
  ///
  /// Currently only mandelbrot has a df2 variant. The range is exclusive of
  /// the CPU fallback threshold.
  bool shouldUseDoubleFloat({
    required String moduleId,
    required double zoom,
  }) {
    return decisionFor(moduleId: moduleId, zoom: zoom).shouldUseDoubleFloat;
  }

  int get hysteresisFrames => _hysteresisFrames;

  /// Auto-scales iteration count with zoom depth for GPU rendering.
  ///
  /// Keeps shallow zoom responsive while increasing detail as zoom grows,
  /// reducing under-iteration artifacts in deep zoom.
  ///
  /// Scaling curve:
  /// - zoom <= 1: unchanged
  /// - zoom > 1: base * (1 + 0.35 * log10(zoom))
  /// - clamped to [4, gpuMaxIterations]
  int scaledGpuIterations({
    required int baseIterations,
    required double zoom,
  }) {
    final safeBase = baseIterations.clamp(4, gpuMaxIterations);
    final depth = _zoomDepthLog10(zoom);
    if (depth == 0.0) return safeBase;

    final factor = 1.0 + 0.35 * depth;
    final scaled = (safeBase * factor).round();
    return scaled.clamp(4, gpuMaxIterations);
  }
}

double _zoomDepthLog10(double zoom) {
  if (zoom.isNaN || zoom <= 1.0) return 0.0;
  if (zoom.isInfinite) return 30.0;
  return (math.log(zoom) / math.ln10).clamp(0.0, 30.0);
}

/// Replayable state for one GPU→CPU deep-zoom hysteresis streak.
///
/// Keeping the transition pure makes the hidden state/order dependence visible:
/// streaks are scoped to one module, below-threshold samples reset immediately,
/// and CPU fallback activates only after enough consecutive above-threshold
/// samples for the same module.
@immutable
class DeepZoomHysteresisState {
  final String? moduleId;
  final int aboveThresholdCount;
  final bool cpuActive;

  const DeepZoomHysteresisState({
    required this.moduleId,
    required this.aboveThresholdCount,
    required this.cpuActive,
  });

  const DeepZoomHysteresisState.initial()
      : moduleId = null,
        aboveThresholdCount = 0,
        cpuActive = false;

  DeepZoomHysteresisState next({
    required String nextModuleId,
    required bool overThreshold,
    required int activationFrames,
  }) {
    assert(activationFrames > 0, 'activationFrames must be positive');
    final sameModule = moduleId == nextModuleId;
    final currentCount = sameModule ? aboveThresholdCount : 0;

    if (!overThreshold) {
      return DeepZoomHysteresisState(
        moduleId: nextModuleId,
        aboveThresholdCount: 0,
        cpuActive: false,
      );
    }

    final nextCount = currentCount + 1;
    return DeepZoomHysteresisState(
      moduleId: nextModuleId,
      aboveThresholdCount: nextCount,
      cpuActive: nextCount >= activationFrames,
    );
  }
}

/// Stateful hysteresis filter for GPU→CPU deep-zoom transitions.
///
/// Wraps [DeepZoomPrecisionPolicy] and requires [policy.hysteresisFrames]
/// consecutive above-threshold evaluations before reporting CPU needed.
/// Drops back to GPU immediately when zoom falls below threshold.
class DeepZoomHysteresis {
  final DeepZoomPrecisionPolicy policy;
  DeepZoomHysteresisState _state = const DeepZoomHysteresisState.initial();

  DeepZoomHysteresis({this.policy = const DeepZoomPrecisionPolicy()});

  DeepZoomHysteresisState get state => _state;

  /// Call this on every zoom change. Returns true if CPU fallback is warranted.
  bool update({required String moduleId, required double zoom}) {
    final overThreshold = policy.shouldUseCpuFallback(
      moduleId: moduleId,
      zoom: zoom,
    );

    _state = _state.next(
      nextModuleId: moduleId,
      overThreshold: overThreshold,
      activationFrames: policy.hysteresisFrames,
    );
    return _state.cpuActive;
  }

  void reset() {
    _state = const DeepZoomHysteresisState.initial();
  }
}

import 'dart:math' as math;
import 'dart:ui';

/// Replayable geometry for the 2D fractal minimap.
///
/// The widget paints a tiny overview and an indicator for the currently visible
/// renderer viewport. Keeping the coordinate math pure lets tests characterize
/// assumptions about zoom samples, minimap size, and renderer aspect ratio
/// without relying on a canvas paint pass.
final class MiniMapGeometry {
  static const double defaultZoom = 1.0;
  static const double minimumIndicatorDimension = 4.0;

  /// Fractal-plane span represented by the minimap overview on each axis.
  static const double overviewWorldSpan = 4.0;

  const MiniMapGeometry._();

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return defaultZoom;
    return zoom;
  }

  static Offset normalizePan(Offset pan) {
    return Offset(
      pan.dx.isFinite ? pan.dx : 0.0,
      pan.dy.isFinite ? pan.dy : 0.0,
    );
  }

  /// Maps an absolute fractal-plane pan center to minimap pixels.
  static Offset centerForPan({
    required Offset pan,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safePan = normalizePan(pan);
    return Offset(
      width / 2.0 + safePan.dx * width / overviewWorldSpan,
      height / 2.0 + safePan.dy * height / overviewWorldSpan,
    );
  }

  /// Inverse of [centerForPan] for tap-to-pan jumps.
  static Offset panForCenter({
    required Offset center,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safeCenter = Offset(
      center.dx.isFinite ? center.dx : width / 2.0,
      center.dy.isFinite ? center.dy : height / 2.0,
    );
    return Offset(
      (safeCenter.dx / width - 0.5) * overviewWorldSpan,
      (safeCenter.dy / height - 0.5) * overviewWorldSpan,
    );
  }

  static Rect viewportRect({
    required Offset pan,
    required double zoom,
    required Size minimapSize,
    required Size viewportSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Rect.zero;

    final safePan = normalizePan(pan);
    final safeZoom = normalizeZoom(zoom);
    final safeViewportSize = _positiveFiniteViewportSize(viewportSize);
    final viewportShortSide = math.min(
      safeViewportSize.width,
      safeViewportSize.height,
    );
    final viewportWidthScale = safeViewportSize.width / viewportShortSide;
    final viewportHeightScale = safeViewportSize.height / viewportShortSide;

    final baseViewportWidth = (2.0 / safeZoom) * (width / overviewWorldSpan);
    final baseViewportHeight = (2.0 / safeZoom) * (height / overviewWorldSpan);
    final center = centerForPan(pan: safePan, minimapSize: minimapSize);

    return Rect.fromCenter(
      center: center,
      width: _clampIndicatorDimension(
        baseViewportWidth * viewportWidthScale,
        width,
      ),
      height: _clampIndicatorDimension(
        baseViewportHeight * viewportHeightScale,
        height,
      ),
    );
  }

  static Offset panForTap({
    required Offset localPosition,
    required Size minimapSize,
    required double zoom,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    // Pan is an absolute fractal-plane center; zoom changes the viewport
    // indicator size, not which overview coordinate a tap selects.
    return panForCenter(center: localPosition, minimapSize: minimapSize);
  }

  static double _positiveFiniteOrZero(double value) {
    return value.isFinite && value > 0.0 ? value : 0.0;
  }

  static Size _positiveFiniteViewportSize(Size size) {
    if (_positiveFiniteOrZero(size.width) == 0.0 ||
        _positiveFiniteOrZero(size.height) == 0.0) {
      return const Size(1, 1);
    }
    return size;
  }

  static double _clampIndicatorDimension(double value, double extent) {
    final lower = math.min(minimumIndicatorDimension, extent);
    if (!value.isFinite || value <= 0.0) return lower;
    return value.clamp(lower, extent).toDouble();
  }
}

import 'dart:ui';

import 'package:flutter_fractals/features/minimap/geometry/minimap_geometry.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('MiniMapGeometry.viewportRect', () {
    test('preserves the rendered viewport aspect ratio', () {
      final rect = MiniMapGeometry.viewportRect(
        pan: Offset.zero,
        zoom: 2.0,
        minimapSize: const Size(240, 240),
        viewportSize: const Size(1600, 900),
      );

      expect(rect.center, const Offset(120, 120));
      expect(rect.width / rect.height, closeTo(16 / 9, 1e-9));
    });

    test('keeps square viewport dimensions compatible with legacy mapping', () {
      final rect = MiniMapGeometry.viewportRect(
        pan: const Offset(1, -1),
        zoom: 2.0,
        minimapSize: const Size(120, 120),
        viewportSize: const Size(600, 600),
      );

      expect(rect.center, const Offset(90, 30));
      expect(rect.width, 30);
      expect(rect.height, 30);
    });

    test('normalizes malformed zoom samples instead of producing NaN rects',
        () {
      final rect = MiniMapGeometry.viewportRect(
        pan: const Offset(double.nan, double.infinity),
        zoom: double.nan,
        minimapSize: const Size(120, 120),
        viewportSize: Size.zero,
      );

      expect(rect.center, const Offset(60, 60));
      expect(rect.width, 60);
      expect(rect.height, 60);
    });
  });

  group('MiniMapGeometry.panForTap', () {
    test('is the inverse of viewport center mapping', () {
      const minimapSize = Size(120, 120);
      const viewportSize = Size(600, 600);
      const tap = Offset(120, 0);

      for (final zoom in [0.5, 1.0, 2.0, 8.0]) {
        final pan = MiniMapGeometry.panForTap(
          localPosition: tap,
          minimapSize: minimapSize,
          zoom: zoom,
        );
        final rect = MiniMapGeometry.viewportRect(
          pan: pan,
          zoom: zoom,
          minimapSize: minimapSize,
          viewportSize: viewportSize,
        );

        expect(rect.center.dx, closeTo(tap.dx, 1e-9), reason: 'zoom=$zoom');
        expect(rect.center.dy, closeTo(tap.dy, 1e-9), reason: 'zoom=$zoom');
      }
    });

    test('maps taps to absolute minimap coordinates independent of zoom', () {
      final zoomedOut = MiniMapGeometry.panForTap(
        localPosition: const Offset(120, 0),
        minimapSize: const Size(120, 120),
        zoom: 0.5,
      );
      final zoomedIn = MiniMapGeometry.panForTap(
        localPosition: const Offset(120, 0),
        minimapSize: const Size(120, 120),
        zoom: 8.0,
      );

      expect(zoomedOut, const Offset(2.0, -2.0));
      expect(zoomedIn, zoomedOut);
    });
  });
}

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/features/minimap/geometry/minimap_geometry.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:provider/provider.dart';
import 'package:vector_math/vector_math.dart' as vm;

/// A minimap overlay showing the current viewport position within a fractal.
class FractalMiniMap extends StatelessWidget {
  final Size viewportSize;
  final double size;
  final bool show3DIndicator;

  const FractalMiniMap({
    super.key,
    required this.viewportSize,
    this.size = 120,
    this.show3DIndicator = true,
  });

  @override
  Widget build(BuildContext context) {
    return Consumer<FractalController>(
      builder: (context, controller, _) {
        final viewState = controller.view;
        final is3D = controller.module.dimension == FractalDimension.threeD;

        if (is3D && show3DIndicator) {
          // For 3D fractals, show zoom indicator only
          return _ZoomIndicator(zoom: viewState.zoom);
        }

        return GestureDetector(
          onTapDown: (details) =>
              _handleTap(context, controller, details.localPosition),
          onPanUpdate: (details) =>
              _handleTap(context, controller, details.localPosition),
          child: Container(
            width: size,
            height: size,
            decoration: BoxDecoration(
              color: Colors.black54,
              borderRadius: BorderRadius.circular(8),
              border: Border.all(color: Colors.white24),
            ),
            child: Stack(
              children: [
                // Grid lines
                CustomPaint(
                  size: Size(size, size),
                  painter: _GridPainter(),
                ),
                // Viewport rectangle
                CustomPaint(
                  size: Size(size, size),
                  painter: _ViewportPainter(
                    pan: Offset(viewState.pan.x, viewState.pan.y),
                    zoom: viewState.zoom,
                    viewportSize: viewportSize,
                  ),
                ),
                // Center dot
                Center(
                  child: Container(
                    width: 6,
                    height: 6,
                    decoration: BoxDecoration(
                      color: Colors.red,
                      shape: BoxShape.circle,
                      border: Border.all(color: Colors.white, width: 1),
                    ),
                  ),
                ),
                // Zoom indicator
                Positioned(
                  bottom: 4,
                  left: 0,
                  right: 0,
                  child: _ZoomPill(zoom: viewState.zoom),
                ),
              ],
            ),
          ),
        );
      },
    );
  }

  void _handleTap(
    BuildContext context,
    FractalController controller,
    Offset localPosition,
  ) {
    final pan = MiniMapGeometry.panForTap(
      localPosition: localPosition,
      minimapSize: Size(size, size),
      zoom: controller.view.zoom,
    );

    controller.updatePan(vm.Vector2(pan.dx, pan.dy));
  }
}

class _ZoomIndicator extends StatelessWidget {
  final double zoom;
  const _ZoomIndicator({required this.zoom});

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
      decoration: BoxDecoration(
        color: Colors.black54,
        borderRadius: BorderRadius.circular(16),
      ),
      child: Text(
        'Zoom: ${zoom.toStringAsFixed(1)}×',
        style: const TextStyle(color: Colors.white, fontSize: 12),
      ),
    );
  }
}

class _ZoomPill extends StatelessWidget {
  final double zoom;
  const _ZoomPill({required this.zoom});

  @override
  Widget build(BuildContext context) {
    return Center(
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
        decoration: BoxDecoration(
          color: Colors.black87,
          borderRadius: BorderRadius.circular(8),
        ),
        child: Text(
          '${zoom.toStringAsFixed(0)}×',
          style: const TextStyle(color: Colors.white70, fontSize: 10),
        ),
      ),
    );
  }
}

class _GridPainter extends CustomPainter {
  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = Colors.white12
      ..strokeWidth = 0.5;

    // Draw grid
    for (var i = 1; i < 4; i++) {
      final x = size.width * i / 4;
      final y = size.height * i / 4;
      canvas.drawLine(Offset(x, 0), Offset(x, size.height), paint);
      canvas.drawLine(Offset(0, y), Offset(size.width, y), paint);
    }
  }

  @override
  bool shouldRepaint(covariant CustomPainter oldDelegate) => false;
}

class _ViewportPainter extends CustomPainter {
  final Offset pan;
  final double zoom;
  final Size viewportSize;

  _ViewportPainter({
    required this.pan,
    required this.zoom,
    required this.viewportSize,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = Colors.cyan
      ..style = PaintingStyle.stroke
      ..strokeWidth = 2;

    final rect = MiniMapGeometry.viewportRect(
      pan: pan,
      zoom: zoom,
      minimapSize: size,
      viewportSize: viewportSize,
    );

    canvas.drawRect(rect, paint);
  }

  @override
  bool shouldRepaint(covariant _ViewportPainter oldDelegate) {
    return pan != oldDelegate.pan ||
        zoom != oldDelegate.zoom ||
        viewportSize != oldDelegate.viewportSize;
  }
}

// A small lexer for a restricted Fractint-like .frm subset.
//
// Supported tokens (initial subset):
// - identifiers: [A-Za-z_][A-Za-z0-9_]*
// - numbers: 123, 1.23, .5, 1e-3
// - punctuation: { } ( ) , : = + - * /
// - comments: ; to end of line

enum FrmTokKind {
  ident,
  number,
  lBrace,
  rBrace,
  lParen,
  rParen,
  comma,
  colon,
  eq,
  plus,
  minus,
  star,
  slash,
  newline,
  eof,
}

final class FrmTok {
  const FrmTok(this.kind, this.lexeme, this.offset);

  final FrmTokKind kind;
  final String lexeme;
  final int offset;

  @override
  String toString() => '$kind("$lexeme")@$offset';
}

final class FrmLexer {
  FrmLexer(this.src);

  final String src;
  int _i = 0;

  List<FrmTok> tokenize() {
    final out = <FrmTok>[];
    while (true) {
      final tok = _next();
      out.add(tok);
      if (tok.kind == FrmTokKind.eof) return out;
    }
  }

  FrmTok _next() {
    _skipSpaces();
    if (_i >= src.length) return FrmTok(FrmTokKind.eof, '', _i);

    final c = src.codeUnitAt(_i);

    // newline
    if (c == 0x0A) {
      _i++;
      return FrmTok(FrmTokKind.newline, '\n', _i - 1);
    }
    if (c == 0x0D) {
      // CRLF or CR
      final start = _i;
      _i++;
      if (_i < src.length && src.codeUnitAt(_i) == 0x0A) _i++;
      return FrmTok(FrmTokKind.newline, '\n', start);
    }

    // comment ;...
    if (c == 0x3B) {
      while (_i < src.length) {
        final cc = src.codeUnitAt(_i);
        if (cc == 0x0A || cc == 0x0D) break;
        _i++;
      }
      // emit newline separately in next call
      return _next();
    }

    switch (c) {
      case 0x7B: // {
        _i++;
        return FrmTok(FrmTokKind.lBrace, '{', _i - 1);
      case 0x7D: // }
        _i++;
        return FrmTok(FrmTokKind.rBrace, '}', _i - 1);
      case 0x28: // (
        _i++;
        return FrmTok(FrmTokKind.lParen, '(', _i - 1);
      case 0x29: // )
        _i++;
        return FrmTok(FrmTokKind.rParen, ')', _i - 1);
      case 0x2C: // ,
        _i++;
        return FrmTok(FrmTokKind.comma, ',', _i - 1);
      case 0x3A: // :
        _i++;
        return FrmTok(FrmTokKind.colon, ':', _i - 1);
      case 0x3D: // =
        _i++;
        return FrmTok(FrmTokKind.eq, '=', _i - 1);
      case 0x2B: // +
        _i++;
        return FrmTok(FrmTokKind.plus, '+', _i - 1);
      case 0x2D: // -
        _i++;
        return FrmTok(FrmTokKind.minus, '-', _i - 1);
      case 0x2A: // *
        _i++;
        return FrmTok(FrmTokKind.star, '*', _i - 1);
      case 0x2F: // /
        _i++;
        return FrmTok(FrmTokKind.slash, '/', _i - 1);
    }

    if (_isDigit(c) || c == 0x2E /* . */) {
      return _number();
    }

    if (_isAlpha(c) || c == 0x5F /* _ */) {
      return _ident();
    }

    throw FormatException('Unexpected character: ${String.fromCharCode(c)}', src, _i);
  }

  void _skipSpaces() {
    while (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (c == 0x20 || c == 0x09) {
        _i++;
        continue;
      }
      break;
    }
  }

  FrmTok _ident() {
    final start = _i;
    _i++;
    while (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (_isAlphaNum(c) || c == 0x5F) {
        _i++;
      } else {
        break;
      }
    }
    return FrmTok(FrmTokKind.ident, src.substring(start, _i), start);
  }

  FrmTok _number() {
    final start = _i;

    bool sawDigit = false;

    // int part or leading '.'
    if (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
      sawDigit = true;
      while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
        _i++;
      }
    }

    // decimal
    if (_i < src.length && src.codeUnitAt(_i) == 0x2E /* . */) {
      _i++;
      while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
        sawDigit = true;
        _i++;
      }
    }

    if (!sawDigit) {
      throw FormatException('Invalid number', src, start);
    }

    // exponent
    if (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (c == 0x65 /* e */ || c == 0x45 /* E */) {
        _i++;
        if (_i < src.length) {
          final s = src.codeUnitAt(_i);
          if (s == 0x2B /* + */ || s == 0x2D /* - */) _i++;
        }
        final expStart = _i;
        while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
          _i++;
        }
        if (expStart == _i) {
          throw FormatException('Invalid exponent', src, expStart);
        }
      }
    }

    return FrmTok(FrmTokKind.number, src.substring(start, _i), start);
  }

  static bool _isDigit(int c) => c >= 0x30 && c <= 0x39;
  static bool _isAlpha(int c) => (c >= 0x41 && c <= 0x5A) || (c >= 0x61 && c <= 0x7A);
  static bool _isAlphaNum(int c) => _isAlpha(c) || _isDigit(c);
}

import 'frm_ast.dart';
import 'frm_lexer.dart';
import 'frm_number_literal.dart';

/// Parser for a small Fractint-style .frm subset.
///
/// Current supported subset:
/// - Multiple formulas per file.
/// - `name { <init-stmts> : <iter-stmts> }`
/// - Stmts: `<ident> = <expr>` separated by newlines.
/// - Expr: numbers, identifiers, (re,im) complex literals, + - * / with parens.
///
/// This is intentionally small; we’ll extend it iteratively with functions,
/// power, comparisons, and bailout conditions once golden iteration tests are in.
bool isFrmStatementBoundary(FrmTokKind kind) =>
    kind == FrmTokKind.newline ||
    kind == FrmTokKind.colon ||
    kind == FrmTokKind.rBrace ||
    kind == FrmTokKind.eof;

bool isFrmFormulaBodyEnd(FrmTokKind kind) =>
    kind == FrmTokKind.rBrace || kind == FrmTokKind.eof;

final class FrmParser {
  FrmParser(String src) : _toks = FrmLexer(src).tokenize();

  final List<FrmTok> _toks;
  int _p = 0;

  FrmFile parseFile() {
    final formulas = <FrmFormula>[];
    _skipNewlines();
    while (!_peekIs(FrmTokKind.eof)) {
      formulas.add(_parseFormula());
      _skipNewlines();
    }
    return FrmFile(formulas);
  }

  FrmFormula _parseFormula() {
    final nameTok = _expect(FrmTokKind.ident, 'Expected formula name');
    _skipNewlines();
    _expect(FrmTokKind.lBrace, 'Expected "{" after formula name');

    final init = <FrmStmt>[];
    final iter = <FrmStmt>[];

    _skipNewlines();
    while (!_peekIs(FrmTokKind.colon)) {
      _expectInitSectionContinues();
      final stmt = _parseStmt();
      init.add(stmt);
      _skipNewlines();
    }

    _expect(FrmTokKind.colon, 'Expected ":" separating init/iter');
    _skipNewlines();

    while (!_peekIs(FrmTokKind.rBrace)) {
      if (_peekIs(FrmTokKind.eof)) {
        throw FormatException('Unterminated formula body', '', _peek().offset);
      }
      final stmt = _parseStmt();
      iter.add(stmt);
      _skipNewlines();
    }

    _expect(FrmTokKind.rBrace, 'Expected "}"');

    return FrmFormula(name: nameTok.lexeme, init: init, iter: iter);
  }

  FrmStmt _parseStmt() {
    final name = _expect(FrmTokKind.ident, 'Expected identifier').lexeme;
    _expect(FrmTokKind.eq, 'Expected "="');
    final expr = _parseExpr();
    _expectStmtBoundary();
    return FrmAssign(name, expr);
  }

  void _expectInitSectionContinues() {
    final tok = _peek();
    if (!isFrmFormulaBodyEnd(tok.kind)) return;
    if (tok.kind == FrmTokKind.eof) {
      throw FormatException('Unterminated formula body', '', tok.offset);
    }
    throw FormatException('Expected ":" in formula body', '', tok.offset);
  }

  void _expectStmtBoundary() {
    final tok = _peek();
    if (!isFrmStatementBoundary(tok.kind)) {
      throw FormatException('Expected newline after statement', '', tok.offset);
    }
  }

  FrmExpr _parseExpr() => _parseAddSub();

  FrmExpr _parseAddSub() {
    var expr = _parseMulDiv();
    while (true) {
      if (_match(FrmTokKind.plus)) {
        expr = FrmBinary(FrmBinaryOp.add, expr, _parseMulDiv());
        continue;
      }
      if (_match(FrmTokKind.minus)) {
        expr = FrmBinary(FrmBinaryOp.sub, expr, _parseMulDiv());
        continue;
      }
      return expr;
    }
  }

  FrmExpr _parseMulDiv() {
    var expr = _parsePrimary();
    while (true) {
      if (_match(FrmTokKind.star)) {
        expr = FrmBinary(FrmBinaryOp.mul, expr, _parsePrimary());
        continue;
      }
      if (_match(FrmTokKind.slash)) {
        expr = FrmBinary(FrmBinaryOp.div, expr, _parsePrimary());
        continue;
      }
      return expr;
    }
  }

  FrmExpr _parsePrimary() {
    if (_match(FrmTokKind.number)) {
      return FrmNumber(FrmNumberLiteral.fromToken(_prev()).parseFinite());
    }

    if (_match(FrmTokKind.ident)) {
      return FrmVar(_prev().lexeme);
    }

    if (_match(FrmTokKind.lParen)) {
      // Could be (expr) or (re,im)
      final first = _parseExpr();
      if (_match(FrmTokKind.comma)) {
        final second = _parseExpr();
        _expect(FrmTokKind.rParen, 'Expected ")"');
        return FrmComplexLiteral(first, second);
      }
      _expect(FrmTokKind.rParen, 'Expected ")"');
      return first;
    }

    if (_match(FrmTokKind.minus)) {
      // unary minus: -x  => (0 - x)
      return FrmBinary(FrmBinaryOp.sub, const FrmNumber(0), _parsePrimary());
    }

    throw FormatException('Expected expression', '', _peek().offset);
  }

  void _skipNewlines() {
    while (_match(FrmTokKind.newline)) {}
  }

  bool _match(FrmTokKind kind) {
    if (_peekIs(kind)) {
      _p++;
      return true;
    }
    return false;
  }

  FrmTok _expect(FrmTokKind kind, String msg) {
    final tok = _peek();
    if (tok.kind != kind) {
      throw FormatException(msg, '', tok.offset);
    }
    _p++;
    return tok;
  }

  FrmTok _peek() => _toks[_p];
  FrmTok _prev() => _toks[_p - 1];
  bool _peekIs(FrmTokKind k) => _peek().kind == k;
}

import 'complex.dart';

sealed class FrmExpr {
  const FrmExpr();

  Complex eval(FrmEvalContext ctx);
}

final class FrmNumber extends FrmExpr {
  const FrmNumber(this.value);

  final double value;

  @override
  Complex eval(FrmEvalContext ctx) => Complex(value, 0);
}

final class FrmComplexLiteral extends FrmExpr {
  const FrmComplexLiteral(this.re, this.im);

  final FrmExpr re;
  final FrmExpr im;

  @override
  Complex eval(FrmEvalContext ctx) {
    final r = evalFrmRealScalarComponent(re, ctx, componentName: 'real');
    final i = evalFrmRealScalarComponent(im, ctx, componentName: 'imaginary');
    return Complex(r, i);
  }
}

/// Evaluates one component of a `(real, imaginary)` literal.
///
/// FRM complex literal components are scalar slots. Silently taking `.re` from
/// a complex-valued expression drops data and makes replay depend on an
/// undocumented truncation rule, so reject that shape at the evaluation seam.
double evalFrmRealScalarComponent(
  FrmExpr expr,
  FrmEvalContext ctx, {
  required String componentName,
}) {
  final value = expr.eval(ctx);
  if (value.im == 0.0) return value.re;
  throw StateError(
    'Complex literal components must evaluate to real scalars; '
    '$componentName component was $value',
  );
}

final class FrmVar extends FrmExpr {
  const FrmVar(this.name);

  final String name;

  @override
  Complex eval(FrmEvalContext ctx) =>
      ctx.vars[name] ?? (throw StateError('Unknown var: $name'));
}

enum FrmBinaryOp { add, sub, mul, div }

final class FrmBinary extends FrmExpr {
  const FrmBinary(this.op, this.left, this.right);

  final FrmBinaryOp op;
  final FrmExpr left;
  final FrmExpr right;

  @override
  Complex eval(FrmEvalContext ctx) {
    final a = left.eval(ctx);
    final b = right.eval(ctx);
    return switch (op) {
      FrmBinaryOp.add => a + b,
      FrmBinaryOp.sub => a - b,
      FrmBinaryOp.mul => a * b,
      FrmBinaryOp.div => a / b,
    };
  }
}

sealed class FrmStmt {
  const FrmStmt();

  void run(FrmEvalContext ctx);
}

final class FrmAssign extends FrmStmt {
  const FrmAssign(this.name, this.expr);

  final String name;
  final FrmExpr expr;

  @override
  void run(FrmEvalContext ctx) {
    ctx.vars[name] = expr.eval(ctx);
  }
}

/// Execution context for a single pixel / iteration.
final class FrmEvalContext {
  FrmEvalContext({required this.vars});

  final Map<String, Complex> vars;
}

final class FrmFormula {
  FrmFormula({
    required this.name,
    required Iterable<FrmStmt> init,
    required Iterable<FrmStmt> iter,
  })  : init = List.unmodifiable(init),
        iter = List.unmodifiable(iter);

  final String name;

  /// Statements before `:`
  final List<FrmStmt> init;

  /// Statements after `:`
  final List<FrmStmt> iter;
}

final class FrmFile {
  FrmFile(Iterable<FrmFormula> formulas)
      : formulas = List.unmodifiable(formulas);

  final List<FrmFormula> formulas;
}

import 'frm_lexer.dart';

/// Replayable numeric-literal contract for the FRM subset.
///
/// The lexer validates numeric syntax, but `double.parse` can still promote
/// very large exponents (for example `1e999`) to Infinity. FRM evaluation only
/// has finite complex scalars, so reject non-finite literals at the parser
/// boundary before they become hidden NaN/Infinity state.
final class FrmNumberLiteral {
  const FrmNumberLiteral({required this.lexeme, required this.offset});

  factory FrmNumberLiteral.fromToken(FrmTok token) {
    assert(token.kind == FrmTokKind.number, 'expected number token');
    return FrmNumberLiteral(lexeme: token.lexeme, offset: token.offset);
  }

  final String lexeme;
  final int offset;

  double parseFinite() {
    final value = double.parse(lexeme);
    if (value.isFinite) return value;
    throw FormatException('Numeric literal must be finite', lexeme, offset);
  }
}

/// Minimal complex number type for CPU-side formula evaluation.
///
/// We keep this tiny and allocation-light so we can evolve it into a proper
/// iteration engine later.
class Complex {
  const Complex(this.re, this.im);

  final double re;
  final double im;

  Complex operator +(Complex other) => Complex(re + other.re, im + other.im);
  Complex operator -(Complex other) => Complex(re - other.re, im - other.im);

  Complex operator *(Complex other) => Complex(
        re * other.re - im * other.im,
        re * other.im + im * other.re,
      );

  Complex operator /(Complex other) {
    final denom = ComplexDivisionContract.denominatorFor(other);
    return Complex(
      (re * other.re + im * other.im) / denom,
      (im * other.re - re * other.im) / denom,
    );
  }

  bool get isFinite => re.isFinite && im.isFinite;

  Complex scale(double s) => Complex(re * s, im * s);

  double abs2() => re * re + im * im;

  @override
  String toString() => '($re,$im)';
}

/// Replayable denominator contract for complex division.
///
/// FRM evaluation is finite-state: a zero or non-finite divisor previously
/// leaked Infinity/NaN into the variable map. Keep that invariant at the
/// arithmetic seam so parser/evaluator tests can replay malformed formulas.
final class ComplexDivisionContract {
  const ComplexDivisionContract._();

  static double denominatorFor(Complex divisor) {
    final denominator = divisor.abs2();
    if (!divisor.isFinite || denominator == 0.0 || denominator.isNaN) {
      throw StateError(
        'Complex divisor must be finite and non-zero: $divisor',
      );
    }
    return denominator;
  }
}

